content.problemStatement:
What will be the output of the following code, which calculates the number of students present in a class based on the total number of students and a default absentee rate of 10%?"

```cpp
#include 
using namespace std;

// Function to calculate the total number of students present after applying a default absentee rate
int calculatePresentStudents(int totalStudents, int absentRate = 10) {
    return totalStudents - (totalStudents * absentRate / 100);
}

int main() {
    int totalStudents = 40;

    // Call the function with default absentee rate (10%)
    int presentStudents = calculatePresentStudents(totalStudents);  
    cout << "Students present: " << presentStudents << endl;

    return 0;
}

